<?php
require_once __DIR__.'/config/auth.php'; require_login(); $user=current_user();
$type=$_POST['type']??'Link';$title=trim($_POST['title']??'');$description=trim($_POST['description']??'');$category=trim($_POST['category']??'');$tags=trim($_POST['tags']??'');$visibility=($_POST['visibility']??'Private')==='Public'?'Public':'Private';$link_url=trim($_POST['link_url']??'');$note_content=trim($_POST['note_content']??'');$file_path=null;$original_filename=null;
if($type==='Link'){ if(!$link_url){header('Location: dashboard.php?ok='.urlencode('Link is required.'));exit;} if(!$title){$p=parse_url($link_url);$base=$p['host']??'Untitled link';$path=trim($p['path']??'','/');$title=$path?str_replace(['-','_'],' ',basename($path)):$base;} }
elseif($type==='Note'){ if(!$note_content){header('Location: dashboard.php?ok='.urlencode('Note is empty.'));exit;} if(!$title)$title=mb_strimwidth($note_content,0,40,'…'); }
else{ $type='Unknown'; if(!empty($_FILES['file']['name'])&&($_FILES['file']['error']??1)===0){$name=$_FILES['file']['name'];$tmp=$_FILES['file']['tmp_name'];$ext=strtolower(pathinfo($name,PATHINFO_EXTENSION));$mime=mime_content_type($tmp);$allowed=['jpg','jpeg','png','gif','webp','pdf']; if(in_array($ext,$allowed,true)){ if(str_contains((string)$mime,'image/'))$type='Image'; if($mime==='application/pdf'||$ext==='pdf')$type='PDF'; $safe=uniqid('ll_',true).'.'.$ext; if(!is_dir(__DIR__.'/uploads'))mkdir(__DIR__.'/uploads',0777,true); move_uploaded_file($tmp,__DIR__.'/uploads/'.$safe);$file_path='uploads/'.$safe;$original_filename=$name;if(!$title)$title=pathinfo($name,PATHINFO_FILENAME);}} if(!$file_path){header('Location: dashboard.php?ok='.urlencode('Choose an image or PDF first.'));exit;} }
if(!$title)$title='Untitled item';$stmt=db()->prepare('INSERT INTO cards (user_id,title,description,type,file_path,original_filename,link_url,note_content,category,tags,visibility) VALUES (?,?,?,?,?,?,?,?,?,?,?)');$stmt->bind_param('issssssssss',$user['id'],$title,$description,$type,$file_path,$original_filename,$link_url,$note_content,$category,$tags,$visibility);$stmt->execute();header('Location: dashboard.php?ok='.urlencode('Item saved to Link-Locker.'));
?>